def topological_sort(graph):
    # Step 1: Identify all nodes with no incoming edges (in-degrees of zero) and add them to the queue (initially empty)
    in_degree = {u: 0 for u in graph}
    for u in graph:
        for v in graph[u]:
            in_degree[v] += 1
    sources = [u for u in in_degree if in_degree[u] == 0]

    # Step 2: Initialize the ordering with these nodes (items to be processed)
    order = []

    # Process each source node, decrementing its in-degrees and adding it to the queue when they hit zero
    while sources:
        u = sources.pop(0)
        order.append(u)
        for v in graph[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                sources.append(v)

    # Check for cycles; if not all nodes are included, a cycle exists (not all topological ordering is possible)
    if len(order) < len(graph):
        raise Exception("Graph has a cycle, no topological sorting possible")

    return order

# Example usage:
if __name__ == "__main__":
    graph = {
        'A': ['B', 'C'],
        'B': ['D', 'E'],
        'C': ['F'],
        'D': [],
        'E': ['F'],
        'F': []
    }

    try:
        sorted_nodes = topological_sort(graph)
        print(sorted_nodes)  # Output might be something like ['A', 'C', 'B', 'E', 'D', 'F']
    except Exception as e:
        print(e)
```
